jQuery(".toggler-block ").click(function() {
    $(".menu-block").slideToggle()
}),
jQuery(".toggler-block").click(function() {
    $(".icon").toggleClass("icons")
}),
$("#setting-dropdown").tooltip(),
$("#search-dropdown").tooltip(),
$("#example").tooltip(),
$("#ex").tooltip(),
$("#info").tooltip(),
$("#cart-tooltip").tooltip(),
$("#account-menu").tooltip(),
$(document).ready(function() {
    $(".adds").click(function() {
        $("#myModal").modal("show")
    })
}),
$(document).on("click.bs.dropdown.data-api", "#info-menu, #cart-modal, #search, #blogs-dropdown, #m, #account-link", function(o) {
    o.stopPropagation()
}),
$(document).ready(function() {
    $(".minus").click(function() {
        var o = $(this).parent().find(".input_amount")
          , n = parseInt(o.val()) - 1;
        return n = n < 1 ? 1 : n,
        o.val(n),
        o.change(),
        !1
    }),
    $(".plus").click(function() {
        var o = $(this).parent().find(".input_amount");
        return o.val(parseInt(o.val()) + 1),
        o.change(),
        !1
    })
}),
$(document).ready(function() {
    $(".wrapper").append('<a href="#" id="go-top"></a>')
}),
$(function() {
    $.fn.scrollToTop = function() {
        $(this).hide().removeAttr("href"),
        "250" <= $(window).scrollTop() && $(this).fadeIn("slow");
        var o = $(this);
        $(window).scroll(function() {
            $(window).scrollTop() <= "250" ? $(o).fadeOut("slow") : $(o).fadeIn("slow")
        }),
        $(this).click(function() {
            $("html, body").animate({
                scrollTop: 0
            }, "slow")
        })
    }
}),
$(function() {
    $("#go-top").scrollToTop()
});
